#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int total = 2 * N;
        long long first, x; bool allEqual = true;
        for(int i=0;i<total;i++){
            scanf("%lld", &x);
            if(i==0) first = x;
            else if(x != first) allEqual = false;
        }
        if(N==1 || !allEqual) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

