import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        total = 2 * N
        first = next(it)
        all_equal = True
        for _ in range(1, total):
            v = next(it)
            if v != first:
                all_equal = False
        if N == 1 or not all_equal:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

